void SoundTest(void){
	while(1){
		wr8(REG_VOL_SOUND,0xFF);
		wr32(REG_GPIOX_DIR, 0x00008004);
		volatile uint32_t delei;
		while(1){
			wr32(REG_GPIOX, 0x00008004); // enable amp
			wr16(REG_SOUND, (0x6C<< 8) | 0x41);
			wr8(REG_PLAY, 1);
			delei = 10000000;
			while(delei--);
			wr32(REG_GPIOX, 0x00008000); // disable amp
			wr8(REG_PLAY, 0);
			wr16(REG_SOUND, 0x0);
			wr8(REG_PLAY, 1);
			delei = 10000000;
			while(delei--);
		}
	}
}

void trailingArray(){
	double theta = 0;
	double deg = 0;
	for(int i=0; i<151; i++){
		deg = 203.0 - ((double)(i / 160.0)) * 241.0;
		if(deg < 0){
			deg += 360.0;
		}
		theta = deg * PI / 180.0;
		trail_x[i] = cos(theta);
		trail_y[i] = sin(theta);
	}
}

void Display_Test(uint8_t Address, uint8_t Minutes, uint8_t Seconds, uint32_t Miliseconds){
	static uint8_t Battery_Percentage = 0, Speed = 0, Brake = 0, Acceleration = 0;
	static uint16_t Inverter_Temperature = 0, Motor_Temperature = 0, Cell_Voltage = 0, Cell_Temperature = 0, Total_Current = 0, Total_Voltage = 0;

	volatile uint32_t delay = 35000;
	while(delay--);
	Display_Update(Acceleration, Brake, Battery_Percentage, Motor_Temperature, Inverter_Temperature, Speed, Cell_Voltage, Cell_Temperature, Total_Current, Total_Voltage, Address, Minutes, Seconds, Miliseconds);
	Battery_Percentage++;
	Motor_Temperature++;
	Inverter_Temperature++;
	Cell_Voltage+=2;
	Cell_Temperature+=3;
	Battery_Percentage %= 101;
	Motor_Temperature %= 100;
	Inverter_Temperature %= 100;
	Cell_Voltage %= 501;
	Cell_Temperature %=801;
	Speed++;
	Speed %= 151;
	Total_Current++;
	Total_Current %= 351;
	Total_Voltage += 2;
	Total_Voltage %= 601;
	Acceleration++;
	Acceleration %= 110;
	Brake++;
	Brake %= 110;
}

